import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - nextGeneration", () => {
  it.todo("should return empty array for empty grid");
  it.todo("should kill a single live cell (underpopulation)");
  it.todo("should kill two adjacent live cells (each has only 1 neighbor)");
  it.todo("should preserve a block pattern [(0,0),(1,0),(0,1),(1,1)] as still life");
  it.todo("should transform a vertical blinker [(0,0),(0,1),(0,2)] into a horizontal blinker [(-1,1),(0,1),(1,1)]");
  it.todo("should kill a live cell with 4 live neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
  it.todo("should handle negative coordinates correctly");
});
